async function seed() {
  console.log("Seeding blog posts...");

  const existing = await db.select({ id: blogPostsTable.id }).from(blogPostsTable);
  if (existing.length > 0) {
    console.log(`Found ${existing.length} existing blog posts — skipping blog seed.`);
  } else {
    const chunks = [];
    for (let i = 0; i < blogPosts.length; i += 10) {
      chunks.push(blogPosts.slice(i, i + 10));
    }
    for (const chunk of chunks) {
      await db.insert(blogPostsTable).values(chunk.map(p => ({
        ...p,
        tags: p.tags,
      })));
    }
    console.log(`Inserted ${blogPosts.length} blog posts.`);
  }

  console.log("Seeding KB articles...");
  const existingKb = await db.select({ id: kbArticlesTable.id }).from(kbArticlesTable);
  if (existingKb.length > 0) {
    console.log(`Found ${existingKb.length} existing KB articles — skipping KB seed.`);
  } else {
    const kbChunks = [];
    for (let i = 0; i < kbArticles.length; i += 10) {
      kbChunks.push(kbArticles.slice(i, i + 10));
    }
    for (const chunk of kbChunks) {
      await db.insert(kbArticlesTable).values(chunk.map(a => ({
        ...a,
        tags: a.tags,
      })));
    }
    console.log(`Inserted ${kbArticles.length} KB articles.`);
  }

  console.log("Seed complete.");
  process.exit(0);
}

seed().catch(e => { console.error(e); process.exit(1); });
